func agingLabelColor(label string) string {
	switch label {
	case "Current":
		return "bg-lime-400"
	case "1-30 days":
		return "bg-amber-400"
	case "31-60 days":
		return "bg-orange-400"
	case "61-90 days":
		return "bg-red-400"
	default:
		return "bg-red-600"
	}
}

func agingAmountColor(label string) string {
	switch label {
	case "Current":
		return "text-lime-400"
	case "1-30 days":
		return "text-amber-400"
	case "31-60 days":
		return "text-orange-400"
	case "61-90 days":
		return "text-red-400"
	default:
		return "text-red-500"
	}
}

